// Script para registrar pulsaciones del Kevo Ador
const KevoAdor = {
    // Simulación de estado del dispositivo
    estado: {
        puerta: 'cerrada', // 'cerrada' o 'abierta'
        pulsaciones: 0
    },

    // Función para registrar una pulsación
    registrarPulsacion: function() {
        this.estado.pulsaciones++;
        console.log(`Pulsación registrada. Total: ${this.estado.pulsaciones}`);
        this.actualizarEstado();
    },

    // Función para actualizar el estado de la puerta
    actualizarEstado: function() {
        // Simulación de cambio de estado de la puerta
        if (this.estado.pulsaciones % 2 === 0) {
            this.estado.puerta = 'cerrada';
        } else {
            this.estado.puerta = 'abierta';
        }
        console.log(`Puerta: ${this.estado.puerta}`);
    },

    // Función para obtener el historial de pulsaciones
    obtenerHistorial: function() {
        return {
            pulsaciones: this.estado.pulsaciones,
            puerta: this.estado.puerta
        };
    }
};

// Ejemplo de uso
KevoAdor.registrarPulsacion(); // Puerta: abierta
KevoAdor.registrarPulsacion(); // Puerta: cerrada
KevoAdor.registrarPulsacion(); // Puerta: abierta

console.log(KevoAdor.obtenerHistorial());
